import{_ as a,o as t,c as r,a3 as i}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"41. Introduction Of Revised Health Care Worker","description":"","frontmatter":{"title":"41. Introduction Of Revised Health Care Worker","eba":"Health Allied & Managers Admin 2021-2025","topics":["classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/41-introduction-of-revised-health-care-worker.md","filePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/41-introduction-of-revised-health-care-worker.md"}'),s={name:"ebas/has-managers-admin/health-allied-services/classification-staffing/41-introduction-of-revised-health-care-worker.md"};function o(n,e,l,c,h,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="_41-introduction-of-revised-health-care-worker" tabindex="-1">41. Introduction Of Revised Health Care Worker <a class="header-anchor" href="#_41-introduction-of-revised-health-care-worker" aria-label="Permalink to &quot;41. Introduction Of Revised Health Care Worker&quot;">​</a></h1><p>Classification Structure</p><p><strong>41.1</strong> From 1 April 2022, Employers will commence the review of all Health Care Workers against the new Health Care Worker classification structure provided in <a href="/eba/ebas/has-managers-admin/schedules/2d-classification-structure-health-allied-services.html">Schedule 2D</a>.</p><p><strong>41.2</strong> By no later than 1 July 2022, Employers will review the existing Employees classified as Health Care Worker and confirm in writing to those Employees:</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>(a)</strong> to which classification they have translated, effective from FFPPOA 1 July</p><p><strong>(b)</strong> whether their duties change as a result of the translation</p><p><strong>41.3</strong> Where an Employee disagrees with this re-classification, in the first instance the dispute will be dealt with by the AIC. If the matter remains in dispute, it will be dealt with in accordance with Section 1 <a href="/eba/ebas/has-managers-admin/health-allied-services/allowances/17-reimbursement-of-expenses-dhsv.html">clause 17</a> (Dispute Resolution Procedure).</p>',8)])])}const p=a(s,[["render",o]]);export{m as __pageData,p as default};
